-- Temporary test galaxy + players. Safe to drop later.
-- V2 keeps only sharque star 30188 and homeworld 21222.

SET NAMES utf8;

-- seed stars








-- seed planets


































































-- one orbit building per star so free_stars keeps the seeded galaxy
SELECT 3001, a.planet_id, 4, 0
  FROM (
    SELECT MIN(id) AS planet_id
      FROM `planets`
     GROUP BY `star_id`
  ) a
 WHERE NOT EXISTS (
    SELECT 1 FROM `orbits_buildings` ob WHERE ob.planet_id = a.planet_id
 );

SET @orbit_lin = INSERT(REPEAT('0', 50), 5, 1, 'T');
SELECT a.planet_id, @orbit_lin
  FROM (
    SELECT MIN(id) AS planet_id
      FROM `planets`
     GROUP BY `star_id`
  ) a
ON DUPLICATE KEY UPDATE `lin` = VALUES(`lin`);

UPDATE `planets` p
 INNER JOIN `orbits_buildings` ob ON ob.planet_id = p.id
   SET p.`occuped` = 1;

-- drop orphan owners from production dump (keep sharque colonies and test)
UPDATE `planets` SET `user_id` = NULL WHERE `user_id` IS NOT NULL AND `user_id` NOT IN (16, 17);

-- test player
ON DUPLICATE KEY UPDATE
  `login` = VALUES(`login`),
  `password` = VALUES(`password`),
  `place_id` = VALUES(`place_id`),
  `place_type` = VALUES(`place_type`),
  `money` = VALUES(`money`),
  `register_date` = VALUES(`register_date`),
  `titul` = VALUES(`titul`),
  `level` = VALUES(`level`),
  `lastlevel` = VALUES(`lastlevel`),
  `volume_music` = VALUES(`volume_music`);

UPDATE `planets` SET `user_id` = 17 WHERE `id` = 21283;

ON DUPLICATE KEY UPDATE
  `lastlogin` = VALUES(`lastlogin`),
  `char_status` = VALUES(`char_status`),
  `char_war` = VALUES(`char_war`),
  `char_level` = VALUES(`char_level`);

UPDATE `users_active` SET `lastlogin` = '2026-07-20 00:00:00' WHERE `id` IN (16, 17);

-- homeworld starter buildings for all owned type-1 planets (gensystem.page)
SELECT 26, p.id, 15, 15, 0
  FROM `planets` p
 WHERE p.type = 1 AND p.user_id IN (16, 17)
   AND NOT EXISTS (SELECT 1 FROM `planets_buildings` pb WHERE pb.planet_id = p.id AND pb.object_id = 26);

SELECT 3001, p.id, 4, 0
  FROM `planets` p
 WHERE p.type = 1 AND p.user_id IN (16, 17)
   AND NOT EXISTS (SELECT 1 FROM `orbits_buildings` ob WHERE ob.planet_id = p.id AND ob.object_id = 3001);

SELECT p.id, '15:15'
  FROM `planets` p
 WHERE p.type = 1 AND p.user_id IN (16, 17)
ON DUPLICATE KEY UPDATE `last_pos` = VALUES(`last_pos`);

SET @map_empty = REPEAT('0', 900);
SET @map_top = INSERT(@map_empty, 466, 1, '6');
SET @map_bld = INSERT(@map_empty, 466, 1, 'C');
SET @orbit_lin = INSERT(REPEAT('0', 50), 5, 1, 'T');

SELECT p.id, @map_top, @map_empty, @map_empty, @map_empty, @map_bld
  FROM `planets` p
 WHERE p.type = 1 AND p.user_id IN (16, 17)
ON DUPLICATE KEY UPDATE
  `top` = VALUES(`top`), `mdl` = VALUES(`mdl`), `btm` = VALUES(`btm`), `fnd` = VALUES(`fnd`), `bld` = VALUES(`bld`);

SELECT p.id, @orbit_lin
  FROM `planets` p
 WHERE p.type = 1 AND p.user_id IN (16, 17)
ON DUPLICATE KEY UPDATE `lin` = VALUES(`lin`);

UPDATE `planets` SET `occuped` = 1 WHERE `type` = 1 AND `user_id` IN (16, 17);

UPDATE `cron` SET `laststart` = NOW() WHERE `id` = 5;
UPDATE `users` SET `last_ip` = '0.0.0.0' WHERE `id` = 1;

-- reset fleets/ships for both test players
DELETE FROM `ships` WHERE `user_id` IN (16, 17);
DELETE FROM `fleets` WHERE `user_id` IN (16, 17);

